select.if:
/* OpenMgmtMapper.selectOpenMgmtListExcel */ SELECT DISTINCT REQ.PROD_TYPE_NM AS prodTypeNm /*상품구분 */ , SUB.CONTRACT_NUM AS contractNum /*계약번호 */ , REQ.RES_NO AS resNo /*예약번호 */ , SUB.SUB_LINK_NAME AS cstmrName /*고객명 */ , SUB.USER_SSN AS ssn /*주민번호 */ , CASE WHEN REQ.CSTMR_TYPE = 'JP' OR REQ.CSTMR_TYPE = 'PP' THEN '' ELSE SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 0, 6) END birth , CASE WHEN REQ.CSTMR_TYPE = 'JP' OR REQ.CSTMR_TYPE = 'PP' THEN '' ELSE SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) END gender , CASE WHEN REQ.CSTMR_TYPE = 'JP' OR REQ.CSTMR_TYPE = 'PP' THEN 0 ELSE FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) END age , REQ.REQ_BUY_TYPE_NM AS reqBuyTypeNm /*구매유형 */ , DECODE(SUB.USIM_TYPE, 'E' , 'Y' , 'N') AS esimYn /*eSIM여부 */ , REQ.FST_ESIM_YN AS fstEsimYn /*최초eSIM여부 */ , REQ.OPER_TYPE AS operType , REQ.OPER_TYPE_NM AS operTypeNm /*업무구분 */ , REQ.MOVE_COMPANY AS moveCompany , REQ.MOVE_COMPANY_NM AS moveCompanyNm /*이동전 통신사 */ , SUB.SUBSCRIBER_NO AS subscriberNo /*휴대폰번호 */ , REQ.FST_RATE_CD AS fstRateCd /*최초요금제코드 */ , REQ.FST_RATE_NM AS fstRateNm /*최초요금제 */ , REQ.LST_RATE_CD AS lstRateCd /*현재요금제코드 */ , REQ.LST_RATE_NM AS lstRateNm /*현재요금제 */ , REQ.SALE_PLCY_NM AS salePlcyNm /*판매정책 */ , TO_NUMBER(SUBSTR(REQ.INST_INFO, 26, 3)) AS enggMnthCnt /*약정개월수 */ , TO_NUMBER(SUBSTR(REQ.INST_INFO, 23, 3)) AS instMnthCnt /*할부개월수 */ , SUB.MODEL_NAME AS lstModelNm /*단말모델명 */ , SUB.INTM_SRL_NO AS lstModelSrlNum /*단말일련번호 */ , NVL(TRIM(SUBSTR(REQ.FST_MODEL_INFO, 21 , 30)), REQ.REQ_USIM_NAME) AS fstModelNm /*최초개통단말 */ , TRIM(SUBSTR(REQ.FST_MODEL_INFO, 51 , 30)) AS fstModelSrlNum /*최초단말일련번호*/ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'MSP0003' AND CD_VAL = SUB.SUB_STATUS) AS subStatusNm /*상태 */ , CASE WHEN SUB.SUB_STATUS = 'C' THEN CASE WHEN 0 = TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '당일개통취소' WHEN 15 > TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '14일이내해지' WHEN 90 > TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '90일이내해지' ELSE '일반해지' END ELSE '' END AS canRsn /*해지사유*/ , FN_GET_CODENM('RCP0007', REQ.ON_OFF_TYPE) AS onOffTypeNm /*모집경로 */ , REQ.OPEN_MARKET_REFERER AS openMarketReferer /*유입경로 */ , REQ.RECOMMEND_FLAG_NM AS recommendFlagNm /*추천인구분 */ , REQ.RECOMMEND_INFO AS recommendInfo /*추천인정보 */ , REQ.REC_YN AS recYn /*녹취여부 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = SUB.OPEN_AGNT_CD AND ROWNUM = 1) AS agentNm /*대리점 */ , REQ.SHOP_CD AS shopCd , REQ.SHOP_NM AS shopNm /*판매점 */ , TO_CHAR(TO_DATE(REQ.REQ_IN_DAY,'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS reqInDay /*신청일자 */ , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD' ), 'YYYY-MM-DD') AS openDt /*개통일자 */ , TO_CHAR(TO_DATE(DECODE(SUB.SUB_STATUS,'C',SUBSTR(SUB.SUB_STATUS_DATE,1,8),''),'YYYYMMDD'),'YYYY-MM-DD') AS tmntDt /*해지일자*/ , SUB.LGL_AGNT_NM AS minorAgentName /*법정대리인 */ , FN_GET_CODENM('RCP9003', SUB.AGNT_REL_DIV_CD) AS minorAgentRelation /*관계 */ , SUB.LGL_AGNT_NO AS minorAgentTel /*대리인연락처 */ , REQ.APP_NM AS appNm /*유해차단APP명 */ , REQ.JOIN_PAY_MTHD_NM AS joinPayMthdNm /*가입비납부방법 */ , REQ.JOIN_PRICE AS joinPrice /*가입비 */ , REQ.USIM_PAY_MTHD_NM AS usimPayMthdNm /*USIM납부방법 */ , REQ.USIM_PRICE AS usimPrice /*USIM비 */ , SUB.OPEN_AGNT_CD AS openAgntCd /*대리점ID */ , TO_NUMBER(SUBSTR(REQ.INST_INFO, 13, 10)) AS instOrginAmnt /*할부원금 */ , CASE WHEN SUBSTR(REQ.SIM_INFO, 36, 1) IN ('A', 'R') THEN (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0058' AND CD_VAL = SUBSTR(REQ.SIM_INFO, 1, 2)) ELSE (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0058' AND CD_VAL = SUBSTR(REQ.INST_INFO, 1, 2)) END AS sprtTpNm /*할인유형 */ , SUBSTR(REQ.INST_INFO, 29, 14) AS grntInsrMngmNo /*보증보험관리번호*/ , SUBSTR(REQ.INST_INFO, 43, 1) AS grntInsrStatCd , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'MSP0011' AND CD_VAL = SUBSTR(REQ.INST_INFO, 43, 1)) AS grntInsrStatNm /*보증보험가입상태*/ , TRIM(SUBSTR(REQ.SIM_INFO, 6, 14)) AS simId /*심플할인ID */ , TO_NUMBER(SUBSTR(REQ.SIM_INFO, 3, 3)) AS simEnggMnthCnt /*심플약정기간 */ , TO_CHAR(TO_DATE(SUBSTR(REQ.SIM_INFO, 20, 8), 'YYYYMMDD'), 'YYYY-MM-DD') AS simStartDt /*심플약정시작일자*/ , TO_CHAR(TO_DATE(SUBSTR(REQ.SIM_INFO, 28, 8), 'YYYYMMDD'), 'YYYY-MM-DD') AS simEndDt /*심플약정종료일자*/ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'MSP0010' AND CD_VAL = SUBSTR(REQ.SIM_INFO, 36, 1)) AS simStatNm /*심플약정상태 */ , REQ.RENTAL_BASE_AMT AS rentalBaseAmt /*렌탈기본료 */ , REQ.RENTAL_BASE_DC_AMT AS rentalBaseDcAmt /*렌탈료할인 */ , REQ.RENTAL_MODEL_CP_AMT AS rentalModelCpAmt /*렌탈단말배상금 */ , REQ.CSTMR_TYPE AS cstmrType /*고객구분 */ , REQ.DVC_CHG_CNT AS dvcChgCnt /*기변횟수*/ , SUBSTR(REQ.DVC_CHG_INFO, 1, 8) AS dvcChgDt /* 기변일자 */ , TRIM(SUBSTR(REQ.DVC_CHG_INFO, 9, 10)) AS dvcModelId /* 기변모델ID */ , TRIM(SUBSTR(REQ.DVC_CHG_INFO, 19, 30)) AS dvcModelNm /* 기변모델명 */ , TRIM(SUBSTR(REQ.DVC_CHG_INFO, 49, 20)) AS dvcIntmSrlNo /* 기변일련번호 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = TRIM(SUBSTR(REQ.DVC_CHG_INFO, 69, 10)) AND ROWNUM = 1) AS dvcAgntNm /* 기변대리점 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0049' AND CD_VAL = SUBSTR(REQ.DVC_CHG_INFO, 79, 4)) AS dvcOperTypeNm /* 기변유형명 */ , TO_NUMBER(SUBSTR(REQ.DVC_CHG_INFO, 83, 10)) AS dvcHndstAmnt /* 기변단말출고가 */ , TO_NUMBER(SUBSTR(REQ.DVC_CHG_INFO, 93, 10)) AS dvcInstOrginAmnt /* 기변단말할부원금 */ , TO_NUMBER(SUBSTR(REQ.DVC_CHG_INFO, 103, 3)) AS dvcInstMnthCnt /* 기변단말할부개월수 */ , TO_NUMBER(SUBSTR(REQ.DVC_CHG_INFO, 106, 3)) AS dvcEnggMnthCnt /* 기변약정개월수 */ , SUBSTR(REQ.DVC_CHG_INFO, 109) AS dvcSalePlcyNm /* 기변판매정책 */ , REQ.OTA_DATE AS otaDate /* OTA등록일자 */ , DECODE(SUB.SUB_STATUS, 'C' ,'', REQ.CATCH_CALL) AS catchcall /* 캐치콜가입일자*/ , REQ.CATCH_CALL_CAN AS catchcallCan /* 캐치콜해지일자*/ , TO_CHAR(TO_DATE(DECODE(SUB.SUB_STATUS,'S',SUBSTR(SUB.SUB_STATUS_DATE,1,8),''),'YYYYMMDD'),'YYYY-MM-DD') AS stopDt /*정지일자*/ , P.PROMOTION_NM AS promotionnm /* 프로모션명 */ , P.STRT_DT AS prmtstrtdt /* 프로모션시작일 */ , P.END_DT AS prmtenddt /* 프로모션종료일 */ , P.BENEFIT_01 AS benefit01 /* 혜택_추가데이터제공여부(Y/N) */ , P.BENEFIT_02 AS benefit02 /* 혜택_추가기본료할인여부(Y/N) */ , P.BENEFIT_03 AS benefit03 /* 혜택_가입비면제여부(Y/N) */ , P.BENEFIT_04 AS benefit04 /* 혜택_유심비면제여부(Y/N) */ , REQ.REAL_SHOP_NM AS realShopNm /* 실 판매점 */ , NVL2(INSR.INSR_NM1, 'Y', 'N') AS insryn1 , INSR.INSR_NM1 AS insrnm1 , NVL(INSR.CLAUSE_INSURANCE_FLAG, 'N') AS clauseinsuranceflag , NVL2(INSR.INSR_NM2, 'Y', 'N') AS insryn2 , INSR.INSR_NM2 AS insrnm2 , CASE WHEN SUB.SUB_STATUS = 'C' THEN FN_GET_CODENM('MSP0012', SUB.SUB_STATUS_RSN_CODE) ELSE NULL END AS subStatusRsnNm /* KT해지사유 */ , NVL((SELECT AGR_YN FROM MSP_MRKT_AGR_MGMT WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND END_DTTM = '99991231235959' ), 'N') AS mrktagryn /* 마케팅동의여부 */ , (SELECT NVL((SELECT NVL(DTL_CD_NM,NP_COMM_CMPN_ID) FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'NSC' AND DTL_CD = NP_COMM_CMPN_ID), (SELECT NVL(DTL_CD_NM,NP_COMM_CMPN_ID) FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'NSC' AND EXPNSN_STR_VAL1 = NP_COMM_CMPN_ID AND USE_YN = 'Y')) FROM MDS_PORTOUT_MST MPM WHERE MPM.CONTRACT_NUM = SUB.CONTRACT_NUM) AS cmpnNm /* 해지후 이동 사업자정보 */ /* 단말보험 */ , (SELECT C.RATE_NM FROM MSP_JUO_FEATURE_INFO A , CMN_GRP_CD_MST B , MSP_RATE_MST C WHERE A.CONTRACT_NUM = SUB.CONTRACT_NUM AND A.SERVICE_TYPE = 'R' AND A.EXPIRATION_DATE >= TO_CHAR(SYSDATE, 'YYYYMMDD') AND A.SOC = B.CD_VAL AND B.CD_VAL = C.RATE_CD AND B.GRP_ID = 'CMN0247' AND ROWNUM = 1 ) AS insrProdNm , CASE WHEN MSD.REQ_USIM_SN IS NOT NULL THEN '직영온라인' ELSE FN_GET_ORGNM(PUM.ORGN_ID) END AS usimOrgNm , FN_GET_ORGNM(PUM.ORGN_ID) AS fstUsimOrgNm , BAN.BAN_ADR_PRIMARY_LN AS banAdrPrimaryLn , R.KTM_REFERER AS ktmReferer , FN_GET_CODENM('RCP9023',FOAI.DGT3_CNTRY_CD) AS cstmrForeignerNation /* 국가 */ , FOAI.SOJN_PRPS_NM AS visaCdNm /* VISA 코드명 */ , REQ.FST_USIM_NO AS fstUsimNum , SUB.ICC_ID AS lstUsimNum , FN_GET_CODENM('RCP2001', R.ONLINE_AUTH_TYPE) AS authType /* 본인인증방식 */ , R.MEMO AS memo , TO_CHAR(NVL(( SELECT TO_DATE(EVNT_TRTM_DT, 'YYYYMMDDHH24MISS') FROM MSP_JUO_SUB_INFO_HIST WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND EVNT_CD = 'NAC' AND ROWNUM = 1), SUB.REG_DTTM), 'YYYY-MM-DD HH24:MI:SS') AS openTime /* 개통시간 */ , PI.BF_COMM_CMPN_ID AS portInCd /* PORT_IN 통신사 코드 */ , PI.BF_COMM_CMPN_NM AS portInCpy /* PORT_IN 통신사명 */ , SUB.USIM_MODNM AS lstUsimModNm /* 현재 USIM 모델명 */ , (SELECT NFC_USIM_YN fROM CMN_INTM_MDL WHERE PRDT_ID = SUB.USIM_MODID AND NFC_USIM_YN IS NOT NULL) AS lstNfcYn /* 현재 USIM NFC 여부 */ , REQ.USIM_MODNM AS fstUsimModNm /* 최초 USIM 모델명 */ , (SELECT NFC_USIM_YN fROM CMN_INTM_MDL WHERE PRDT_ID = REQ.USIM_MODID AND NFC_USIM_YN IS NOT NULL) AS fstNfcYn /* 최초 USIM NFC 여부 */ , CASE SUBSTR(REQ.DIS_PRMT_ID, 1, 1) WHEN 'F' THEN (SELECT '(오프라인) ' || PRMT_NM FROM MSP_DIS_MST WHERE PRMT_ID = REQ.DIS_PRMT_ID) WHEN 'C' THEN (SELECT '(온라인) ' || PRMT_NM FROM MSP_CHRG_PRMT WHERE PRMT_ID = REQ.DIS_PRMT_ID) ELSE '' END AS disPrmtNm /* 평생할인 프로모션명*/ , DECODE(SUB.SUB_STATUS,'S',FN_GET_CODENM('MSP0004',SUB.SUB_STATUS_RSN_CODE),'A','','C','') AS stopRsn /* 정지사유 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'JehuProdType' AND DTL_CD = (SELECT JEHU_TP FROM MSP_CLAUSE_AGREE WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND CLAUSE_TP = '30' AND AGR_YN = 'Y')) AS jehuProdType /*제휴사*/ , SUB.SVC_CNTR_NO AS svcCntrNo /* 서비스 계약번호 */ , SUB.IMEI AS imei , (SELECT RFRN_SBST FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = REQ.SHOP_CD AND TYPE_CD = '30' AND HGHR_ORGN_CD = SUB.OPEN_AGNT_CD AND ROWNUM = 1) AS rfrnSbst /*접점비고 */ , DECODE(SUB.SUB_STATUS, 'C', (SELECT ETC2 FROM CMN_GRP_CD_MST WHERE GRP_ID = 'MSP0012' AND CD_VAL = SUB.SUB_STATUS_RSN_CODE), '') AS canType /*KT해지사유유형*/
, ( SELECT DECODE(B.USIM_NO, NULL, DECODE(C.USIM_NO, NULL, 'N', 'Y'), 'N') FROM MSP_JUO_SUB_INFO A , MSP_PARTNER_USIM_MST B , MSP_DIR_DLVRY_USIM_MST C WHERE 1=1 AND A.CONTRACT_NUM = SUB.CONTRACT_NUM AND A.ICC_ID = B.USIM_NO(+) AND A.ICC_ID = C.USIM_NO(+) AND A.CONTRACT_NUM = C.CONTRACT_NUM(+) ) AS dduYn FROM MSP_JUO_SUB_INFO SUB , MSP_REQUEST_DTL REQ , MSP_PROMOTION_MST P , NMCP_USIM_BUY_TXN@DL_MCP MSD , MSP_PARTNER_USIM_MST PUM , KIS_FN_OPEN_AUTH_INFO FOAI , MSP_REQUEST R , MDS_PORTIN_MST PI , MSP_JUO_BAN_INFO BAN ,( SELECT TRIM(SYS_CONNECT_BY_PATH(DECODE(ETC2, 'N', INSR_NM), ' ')) AS INSR_NM1 , TRIM(SYS_CONNECT_BY_PATH(DECODE(ETC2, 'Y', INSR_NM), ' ')) AS INSR_NM2 , CONTRACT_NUM , TRIM(SYS_CONNECT_BY_PATH(CLAUSE_INSURANCE_FLAG, ' ')) AS CLAUSE_INSURANCE_FLAG FROM ( SELECT A.CONTRACT_NUM , A.INSR_CD , B.CD_DSC AS INSR_NM , B.ETC2 , ROW_NUMBER() OVER (PARTITION BY A.CONTRACT_NUM ORDER BY A.CONTRACT_NUM, A.INSR_CD) AS NUM , COUNT(*) OVER (PARTITION BY A.CONTRACT_NUM) AS CNT , NVL((SELECT MAX(CLAUSE_INSURANCE_FLAG) FROM MSP_CHG_RCPT_MST WHERE CONTRACT_NUM = A.CONTRACT_NUM AND INSR_CD = A.INSR_CD AND TSK_TP = 'INS' AND SEQ_NUM = ( SELECT MAX(SEQ_NUM) FROM MSP_CHG_RCPT_MST WHERE CONTRACT_NUM = A.CONTRACT_NUM AND INSR_CD = A.INSR_CD AND TSK_TP = 'INS') ), D.CLAUSE_INSURANCE_FLAG) AS CLAUSE_INSURANCE_FLAG FROM MSP_INSR_MEMBER_MST A , CMN_GRP_CD_MST B , MSP_JUO_SUB_INFO C , MSP_REQUEST D /* 개통시 신청 */ WHERE A.STAT_CD = 'A' AND B.GRP_ID = 'CMN0246' AND A.INSR_CD = B.CD_VAL AND A.CONTRACT_NUM = C.CONTRACT_NUM
AND C.LST_COM_ACTV_DATE BETWEEN #{lstComActvDateF} AND #{lstComActvDateT}
AND C.SUB_STATUS = #{subStatus}
AND C.OPEN_AGNT_CD = #{cntpntShopId}
AND C.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (C.CONTRACT_NUM = #{searchName} OR C.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND C.SUBSCRIBER_NO = #{searchName}
AND A.CONTRACT_NUM = D.CONTRACT_NUM(+) AND A.INSR_CD = D.INSR_CD(+) ORDER BY A.CONTRACT_NUM, A.INSR_CD, B.ETC2 ) WHERE LEVEL = CNT START WITH NUM=1 CONNECT BY PRIOR CONTRACT_NUM = CONTRACT_NUM AND PRIOR NUM = NUM-1 ) INSR
, ( SELECT CONTRACT_NUM FROM MSP_JUO_MODEL_INFO WHERE INTM_SRL_NO = #{searchName} GROUP BY CONTRACT_NUM ) MDL
WHERE SUB.PPPO = 'PO' AND SUB.CONTRACT_NUM = REQ.CONTRACT_NUM AND SUB.CONTRACT_NUM = INSR.CONTRACT_NUM(+) AND REQ.PROMOTION_CD = P.PROMOTION_CD(+) AND SUB.ICC_ID = MSD.REQ_USIM_SN(+) AND REQ.FST_USIM_NO = PUM.USIM_NO(+) AND SUB.SVC_CNTR_NO = FOAI.SVC_CONT_ID(+) AND REQ.CONTRACT_NUM = R.CONTRACT_NUM(+) AND REQ.RES_NO = R.RES_NO(+) AND SUB.CONTRACT_NUM = PI.CONTRACT_NUM(+) AND SUB.BAN = BAN.BAN
AND SUB.LST_COM_ACTV_DATE BETWEEN #{lstComActvDateF} AND #{lstComActvDateT}
AND SUB.SUB_STATUS = #{subStatus}
AND (SUB.OPEN_AGNT_CD = #{cntpntShopId} OR TRIM(SUBSTR(REQ.DVC_CHG_INFO, 69, 10)) = #{cntpntShopId})
AND REQ.SHOP_CD = #{pAgentCode}
AND REQ.REQ_BUY_TYPE = #{reqBuyTypeS}
AND REQ.ON_OFF_TYPE = #{onOffType}
AND REQ.CSTMR_TYPE = 'NM'
AND REQ.APP_BLCK_AGRM_YN = 'Y'
AND REQ.APP_INST_YN = 'Y'
AND SUB.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (SUB.CONTRACT_NUM = #{searchName} OR SUB.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SUB.SUBSCRIBER_NO = #{searchName}
AND SUB.CONTRACT_NUM = MDL.CONTRACT_NUM
AND REQ.REQUEST_KEY IS NULL
AND EXISTS ( SELECT 1 FROM LGS_TELECOM_IF WHERE SVC_CT_NUM = SUB.CONTRACT_NUM AND LGS_PRCS_YN = 'Y' AND PRDT_TYPE_CD = 'D1' AND TO_DATE(SUBSTR(SVC_OPEN_DTTM, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') < 15 ) AND EXISTS ( SELECT 1 FROM MSP_JUO_MODEL_INFO WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND MODEL_TYPE = 'D1' AND EVNT_CD = 'C07' )
AND REQ.LST_RATE_NM LIKE '%' || #{searchName} || '%'
AND EXISTS ( SELECT 1 FROM MSP_JUO_ADD_INFO WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND SIM_ID IS NOT NULL )
AND EXISTS ( SELECT 1 FROM MSP_JUO_ADD_INFO WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND BL_DC_TYPE = #{sprtTp} )
AND NVL(REQ.PROD_TYPE, '01') = #{prodType}
AND ( REQ.OPER_TYPE = #{operType} OR EXISTS ( SELECT 1 FROM MSP_DVC_CHG_AGNT_HST X, MSP_REQUEST Y WHERE X.REQUEST_KEY = Y.REQUEST_KEY AND X.CONTRACT_NUM = SUB.CONTRACT_NUM AND TO_DATE(SUBSTR(APPL_END_DTTM, 1, 8), 'YYYYMMDD') - TO_DATE(SUBSTR(APPL_STRT_DTTM, 1, 8), 'YYYYMMDD') > 14 AND Y.OPER_TYPE = #{operType} AND SUBSTR(X.APPL_STRT_DTTM, 1, 8) BETWEEN #{lstComActvDateF} AND #{lstComActvDateT} ) )
AND SUB.USIM_TYPE = 'E'
AND PUM.ORGN_ID = #{usimOrgCd}
AND SUBSTR(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), 0, 6) = #{pBirthDayVal}
ORDER BY OPENDT DESC
